1.打开企业微信电脑版点击红框位置添加机器人<br />2.复制地址<br />3.代码环节 Controller<br />@<a target="_blank" href="/member/GetMapping" rel="nofollow noopener">GetMapping</a>(value = "testRobot")<br />public void testRobot() throws IOException {<br />    //VO 这段可以写在业务逻辑层<br />    RobotVo vo = new RobotVo();<br />    //机器人地址<br />    vo.setWebhookAddress("刚才复制的地址");<br />    //1.第一种情况：发送文本消息<br />    // vo.setContent("我发送的消息是：文本消息");<br />    // List&lt;String&gt; memberList = new ArrayList&lt;&gt;();<br />    // memberList.add("@all");<br />    // vo.setMemberList(memberList);<br />    // vo.setMsgType("text");<br /><br />    // 2.第二种情况，发送图片消息<br />    // vo.setMsgType("image");<br />    // vo.setSavePath("C:/Users/Administrator/Desktop/吴彦祖.jpg");<br /><br />    //3.第三种情况，发送机器人消息<br />    vo.setMsgType("news");<br />    vo.setTitle("test");<br />    vo.setDescription("test");<br />    vo.setUrl("url");<br />    // vo.setImageUrl("url")括号中的 url 是上传 oss 返回的路径<br />    vo.setImageUrl("url");<br />    <a target="_blank" href="http://service.run" rel="nofollow noopener">service.run</a>(vo);<br />}<br /><br />4.VO<br />@<a target="_blank" href="/member/Data" rel="nofollow noopener">Data</a><br />public class RobotVo {<br />    /**<br />     * 机器人 id<br />     */<br />    private String robotId;<br />    /**<br />     * 机器人名字<br />     */<br />    private String robotName;<br />    /**<br />     * 当前机器人的 webhook 地址<br />     */<br />    private String webhookAddress;<br />    /**<br />     * 消息类型<br />     */<br />    private String msgType;<br />    /**<br />     * 富文本框里面的内容<br />     */<br />    private String content;<br />    /**<br />     * 涉及发送的人员<br />     */<br />    private List&lt;String&gt; memberList;<br />    /**<br />     * 电话<br />     */<br />    private String mobileList;<br />    /**<br />     * 图片地址<br />     */<br />    private String imageUrl;<br />    /**<br />     * base64 编码后的值<br />     */<br />    private String imageBase64Value;<br /><br />    /**<br />     * 图片 md5 加密后的值<br />     */<br />    private String imageMd5Value;<br /><br />    /**<br />     * 发送消息的标题<br />     */<br />    private String title;<br />    /**<br />     * 发送图文消息的描述信息<br />     */<br />    private String description;<br />    /**<br />     * 图片 url 地址集合<br />     */<br />    private List&lt;String&gt; imageUrlList;<br />    /**<br />     * 图片打开的地址<br />     */<br />    private String url;<br />    /**<br />     * 消息内容集合<br />     */<br />    private List&lt;String&gt; contentList;<br />    /**<br />     * 图片路径<br />     */<br />    private String savePath;<br />}<br /><br />5.Service 接口<br />	/**<br />     * 机器人<br />     * @<a target="_blank" href="/member/param" rel="nofollow noopener">param</a> vo<br />     * @<a target="_blank" href="/member/throws" rel="nofollow noopener">throws</a> IOException<br />     */<br />void run(RobotVo vo) throws IOException;<br /><br />6.Service 业务逻辑<br />    @<a target="_blank" href="/member/Override" rel="nofollow noopener">Override</a><br />    public void run(RobotVo vo) throws IOException {<br />        List&lt;String&gt; memberList = vo.getMemberList();<br />        String jsonData = "";<br />        String mobileList = "";<br />        String strMember = "";<br />        if (vo.getMsgType().equals("text")) {<br />            if (!Strings.isNullOrEmpty(vo.getMobileList())) {<br />                mobileList = vo.getMobileList();<br />            } else {<br />                mobileList = "";<br />            }<br />            for (int i = 0; i &lt; memberList.size(); i++) {<br />                if (i == memberList.size() - 1) {<br />                    strMember += """ + memberList.get(i) + """;<br />                } else {<br />                    strMember += """ + memberList.get(i) + """ + ",";<br />                }<br />            }<br />            String[] members = new String[memberList.size()];<br />            for (int i = 0; i &lt; memberList.size(); i++) {<br />                members[i] = memberList.get(i);<br />            }<br />            jsonData = "{
" +<br />                    "	"msgtype": "" + vo.getMsgType() + "",
" +<br />                    "    "text": {
" +<br />                    "        "content": "" + vo.getContent() + "",
" +<br />                    "        "mentioned_list":[" + strMember + "],
" +<br />                    "        "mentioned_mobile_list":["" + mobileList + ""]
" +<br />                    "    }
" +<br />                    "}";<br /><br />        } else if (vo.getMsgType().equals("image")) {<br />            //图片 base64 加密的值<br />            vo.setImageBase64Value(getImageStr(vo.getSavePath()));<br />            //图片 md5 加密的值<br />            vo.setImageMd5Value(DigestUtils.md5Hex(new FileInputStream(vo.getSavePath())));<br />            jsonData = "{
" +<br />                    "    "msgtype": "" + vo.getMsgType() + "",
" +<br />                    "    "image": {
" +<br />                    "        "base64": "" + vo.getImageBase64Value() + "",
" +<br />                    "        "md5": "" + vo.getImageMd5Value() + ""
" +<br />                    "    }
" +<br />                    "}";<br />        } else if (vo.getMsgType().equals("news")) {<br />            //图片+文字消息<br />            vo.setTitle(!Strings.isNullOrEmpty(vo.getTitle()) ? vo.getTitle() : "");<br />            jsonData = "{
" +<br />                    "    "msgtype": "" + vo.getMsgType() + "",
" +<br />                    "    "news": {
" +<br />                    "       "articles" : [
" +<br />                    "           {
" +<br />                    "               "title" : "" + vo.getTitle() + "",
" +<br />                    "               "description" : "" + vo.getDescription() + "",
" +<br />                    "               "url" : "" + vo.getUrl() + "",
" +<br />                    "               "picurl" : "" + vo.getImageUrl() + ""
" +<br />                    "           }
" +<br />                    "        ]
" +<br />                    "    }
" +<br />                    "}";<br />        }<br />        send(vo.getWebhookAddress(), jsonData);<br />    }<br />7.send 方法<br />  public static JSONObject send(String url, String param) {<br />        PrintWriter out = null;<br />        BufferedReader in = null;<br />        JSONObject jsonObject = null;<br />        String result = "";<br />        try {<br />            URL realUrl = new URL(url);<br />            // 打开和 URL 之间的连接<br />            URLConnection conn = realUrl.openConnection();<br />            // 发送 POST 请求必须设置如下两行<br />            conn.setDoOutput(true);<br />            conn.setDoInput(true);<br />            // 获取 URLConnection 对象对应的输出流（设置请求编码为 UTF-8 ）<br />            out = new PrintWriter(new OutputStreamWriter(conn.getOutputStream(), "UTF-8"));<br />            // 发送请求参数<br />            out.print(param);<br />            // flush 输出流的缓冲<br />            out.flush();<br />            // 获取请求返回数据（设置返回数据编码为 UTF-8 ）<br />            in = new BufferedReader(<br />                    new InputStreamReader(conn.getInputStream(), "UTF-8"));<br />            String line;<br />            while ((line = in.readLine()) != null) {<br />                result += line;<br />            }<br />            jsonObject = JSONObject.parseObject(result);<br />        } catch (IOException e) {<br />            e.printStackTrace();<br />        } finally {<br />            try {<br />                if (out != null) {<br />                    out.close();<br />                }<br />                if (in != null) {<br />                    in.close();<br />                }<br />            } catch (IOException ex) {<br />                ex.printStackTrace();<br />            }<br />        }<br />        return jsonObject;<br />    }<br /><br />这个是在调用官方 api 对接的接口。但是如果想更复杂的功能，比如：得到回调消息，外部群管理，发朋友圈等等。就需要 PC 版企微，c++底层开发了。欢迎技术交流。<br />HWND Qq[]=“2645542961”;<br />wchar_t mesbuff[0x180e];<br /><br />目前已经实现了大部分功能，运行稳定，比如：发各种消息，<br />接收各种消息，外部群内部群管理，下载文件，加好友，发朋友圈等等功能，<br />可提供接口，方便各种语言二次开发，
